const rawText = $json.text;

let cleanedText = rawText
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleanedText);
} catch (error) {
  throw new Error('AI output is not valid JSON: ' + cleanedText);
}

const hashtags = Array.isArray(parsed.hashtags) ? parsed.hashtags : [];

return [
  {
    json: {
      content_angle: parsed.content_angle || '',
      linkedin_post: parsed.linkedin_post || '',
      instagram_caption: parsed.instagram_caption || '',
      instagram_image_prompt: parsed.instagram_image_prompt || '',
      hashtags,
      hashtags_text: hashtags.join(' '),
    }
  }
];
